# %% IMPORTS
from dataclasses import dataclass, field, asdict
from typing import Any

# All declaration
__all__ = [
    "CivVSlotData",
]


# %% DATACLASS DEFINITIONS
@dataclass
class CivVSlotData:
    output_file_id: str
    "Unique ID that identifies the output file generated by for this slot"
    building_sanity: bool = False
    "Whether building sanity is enabled"
    national_wonder_sanity: bool = False
    "Whether national wonder sanity is enabled"
    world_wonder_sanity: bool = False
    "Whether world wonder sanity is enabled"
    unit_sanity: bool = False
    "Whether unit sanity is enabled"
    settler_sanity: bool = False
    "Whether settler sanity is enabled"
    settler_sanity_amount: int = 0
    "Number of settlers in settler sanity"
    promotion_sanity: bool = False
    "Whether promotion sanity is enabled"
    death_link: bool = False
    "Whether death link is enabled"
    death_link_effect_weights: dict[str, int] = field(default_factory=dict)
    "Weights of each death link effect"

    def to_dict(self) -> dict[str, Any]:
        """
        Converts this instance to a dict and returns it.

        """

        return asdict(self)
